import { useState } from "react";
import "../styles/TestimonialsSlider.css";

export default function TestimonialsSlider() {
  const testimonials = [
    { text: "Thynexis delivered exactly what we needed. Highly recommend!", client: "Happy Client 1" },
    { text: "Fantastic service and attention to detail. Would definitely work with them again.", client: "Happy Client 2" },
    { text: "Incredible work! The team at Thynexis exceeded our expectations.", client: "Happy Client 3" },
    { text: "A great experience working with such professionals. Highly skilled and efficient.", client: "Happy Client 4" },
    { text: "The best team we’ve worked with, and we’ve worked with a lot! Highly recommend.", client: "Happy Client 5" },
    { text: "Very professional and responsive. They took our project to the next level!", client: "Happy Client 6" },
    { text: "Top-notch work and great communication throughout the process.", client: "Happy Client 7" },
    { text: "Creative, diligent, and focused. Couldn't ask for more.", client: "Happy Client 8" },
    { text: "Amazing experience from start to finish. They made the process so easy.", client: "Happy Client 9" },
    { text: "We are extremely pleased with the results. Thynexis nailed it.", client: "Happy Client 10" },
    { text: "A pleasure to work with. Would definitely hire them again.", client: "Happy Client 11" },
    { text: "The team at Thynexis went above and beyond our expectations.", client: "Happy Client 12" },
    { text: "Amazing attention to detail and perfect execution!", client: "Happy Client 13" },
    { text: "Outstanding service. We felt truly valued as a client.", client: "Happy Client 14" },
    { text: "Exceeded expectations in all areas. Highly recommend.", client: "Happy Client 15" },
    { text: "They brought our vision to life perfectly. Very happy with the results.", client: "Happy Client 16" },
    { text: "Fantastic communication and project management skills.", client: "Happy Client 17" },
    { text: "They understood exactly what we needed and delivered perfectly.", client: "Happy Client 18" },
    { text: "Highly skilled and great to work with. I can’t recommend them enough.", client: "Happy Client 19" },
    { text: "Thynexis is a game-changer. The results speak for themselves.", client: "Happy Client 20" }
  ];

  const [currentIndex, setCurrentIndex] = useState(0);

  const goToNextTestimonial = () => {
    setCurrentIndex((prevIndex) => (prevIndex + 1) % testimonials.length); // Wrap around
  };

  const goToPrevTestimonial = () => {
    setCurrentIndex((prevIndex) => (prevIndex - 1 + testimonials.length) % testimonials.length); // Wrap around
  };

  return (
    <div className="testimonials-slider">
      <div className="testimonial">
        <p>{testimonials[currentIndex].text}</p>
        <p><strong>- {testimonials[currentIndex].client}</strong></p>
      </div>

      <div className="slider-controls">
        <button onClick={goToPrevTestimonial}>&#8592; Previous</button>
        <button onClick={goToNextTestimonial}>Next &#8594;</button>
      </div>
    </div>
  );
}
